function solve(s) {
    // 1. Calculate character frequencies
    const freq = new Map();
    for (const char of s) {
        freq.set(char, (freq.get(char) || 0) + 1);
    }

    // Helper function to determine the mirror character
    const getMirror = (c) => {
        const code = c.charCodeAt(0);

        // Check for lowercase letter ('a' to 'z')
        if (code >= 97 && code <= 122) {
            // Formula: 97 + 122 - code = 219 - code
            return String.fromCharCode(219 - code);
        } 
        // Check for digit ('0' to '9')
        else if (code >= 48 && code <= 57) {
            const digit = parseInt(c);
            const mirrorDigit = 9 - digit;
            return String(mirrorDigit);
        }
        return null; // Should not happen based on constraints
    };

    let totalSum = 0;
    // Use a set to track pairs {min_char, max_char} that have already been processed
    const processedPairs = new Set();

    // 2. Iterate over unique characters present in s
    for (const c of freq.keys()) {
        const m = getMirror(c);

        if (m === null) continue;

        // Normalize pair representation: always store (smaller char, larger char)
        const char1 = c < m ? c : m;
        const char2 = c < m ? m : c;

        // Create a unique key for the pair (e.g., "a#z")
        const pairKey = char1 + '#' + char2;

        if (processedPairs.has(pairKey)) {
            continue;
        }

        // Mark as processed
        processedPairs.add(pairKey);

        // Get frequencies. If m is not in s, freq(m) is 0.
        const freqC = freq.get(c);
        const freqM = freq.get(m) || 0;

        // Calculate absolute difference and add to the sum
        totalSum += Math.abs(freqC - freqM);
    }

    return totalSum;
}

